mapper.update:
UPDATE course_request cr
SET
  cr.status = #{status},
  cr.processed_at = #{processedAt},
  cr.processed_by_professor_id = (
    SELECT p.professor_id
    FROM professor p
    WHERE p.user_id = #{professorUserId}
  )
WHERE cr.status = 'PENDING'
  AND TO_CHAR(cr.request_id) = #{requestId}
  AND EXISTS (
    SELECT 1
    FROM course_section cs
    JOIN course c ON c.course_id = cs.course_id
    JOIN professor p ON p.professor_id = cs.professor_id
    WHERE cs.section_id = cr.section_id
      AND c.course_code = #{courseId}
      AND p.user_id = #{professorUserId}
  )
